// QRCodeStore 存储生成的二维码（内存存储）
var QRCodeStore = make(map[string]*StoredQRCode)

// StoredQRCode 存储的二维码数据
type StoredQRCode struct {
	ID      string
	Data    []byte
	DataStr string
	Size    int
}

// GenerateQRCode .
// @router /qrcode/generate [POST]
func GenerateQRCode(ctx context.Context, c *app.RequestContext) {
	var err error
	var req qrcode.GenerateQRCodeReq
	err = c.BindAndValidate(&req)
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": err.Error(),
		})
		return
	}

	// 验证二维码数据
	if req.Data == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "二维码数据不能为空",
		})
		return
	}

	// 设置默认尺寸
	size := int(req.Size)
	if size <= 0 {
		size = 256
	}

	// 验证数据长度
	if len(req.Data) > 4296 {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "二维码数据过长，最大支持4296个字符",
		})
		return
	}

	// 生成二维码
	pngData, err := qrcodeservice.GenerateQRCode(req.Data, size)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "生成二维码失败: " + err.Error(),
		})
		return
	}

	// 生成唯一ID
	id := qrcodeservice.GenerateQRCodeID()

	// 存储二维码数据
	QRCodeStore[id] = &StoredQRCode{
		ID:      id,
		Data:    pngData,
		DataStr: req.Data,
		Size:    size,
	}

	// 构建响应
	resp := &qrcode.GenerateQRCodeResp{
		Code:    200,
		Message: "生成成功",
		Data: &qrcode.QRCodeData{
			Id:   id,
			Data: req.Data,
			Size: req.Size,
		},
	}

	// 如果需要返回base64数据
	if req.ReturnBase64 {
		base64Data, err := qrcodeservice.GenerateQRCodeBase64(req.Data, size)
		if err != nil {
			c.JSON(consts.StatusInternalServerError, map[string]interface{}{
				"code":    500,
				"message": "生成base64数据失败: " + err.Error(),
			})
			return
		}
		resp.Data.Base64Data = base64Data
	} else {
		// 返回图片URL
		resp.Data.ImageUrl = fmt.Sprintf("/qrcode/%s", id)
	}

	c.JSON(consts.StatusOK, resp)
}

// GetQRCode .
// @router /qrcode/:id [GET]
func GetQRCode(ctx context.Context, c *app.RequestContext) {
	var err error
	var req qrcode.GetQRCodeReq
	err = c.BindAndValidate(&req)
	if err != nil {
		c.String(consts.StatusBadRequest, err.Error())
		return
	}

	// 检查二维码是否存在
	storedQR, exists := QRCodeStore[req.Id]
	if !exists {
		c.JSON(consts.StatusNotFound, map[string]interface{}{
			"code":    404,
			"message": "二维码不存在",
		})
		return
	}

	// 返回PNG图片
	c.SetContentType("image/png")
	c.Write(storedQR.Data)
}
